import React, { Component } from 'react';
import MangaData from '../../Data/MangaData.js';
class AllManga extends Component {
    render() {
        return (
        <div className="latest-update">
          <h1 style={{textAlign: 'center', padding: '1em', margin: 0, color: 'rgb(255, 115, 0)'}}>All manga</h1>
          <div className="manga-info">{
              MangaData.map((value,key)=>{
                return(
                  <div className="manga-info">
                    <div className="children-manga">
                      <img src={value.MangaImage} alt=" " />
                      <a href>Manga 1</a>
                    </div>
                    <a href={this.props.meo}>Chapter 1</a>
                    <p>1 hour<br />ago</p>
                  </div>
                )
              })
            }
          </div>
          <div className="page-section">
            <a href>1</a>
            <a href>2</a>
            <a href>3</a>
            <a href>4</a>
            <a href>5</a>
            <p>...</p>
            <a href>Last</a>
          </div>
          </div>
        );
    }
}

export default AllManga;
